#include <stdio.h>

int main() {
    int T; 
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; 
        scanf("%d", &N);
        for (int i = 0; i < N; ++i) {
            if (i) printf(" ");
            printf("%d", 2*i + 1);
        }
        printf("\n");
    }
    return 0;
}

